from langflow.custom import Component
from langflow.io import MessageTextInput, Output
from langflow.schema.message import Message
import requests
import json
import urllib3
urllib3.disable_warnings()

class WazuhAPIComponent(Component):
    display_name = "Wazuh Data Fetcher"
    description = "Fetches real data from Wazuh"

    inputs = [
        MessageTextInput(
            name="user_question",
            display_name="User Question"
        )
    ]

    outputs = [
        Output(
            display_name="Wazuh Data",
            name="wazuh_data",
            method="fetch_wazuh_data"
        )
    ]

    MANAGER_URL  = "https://172.21.252.96:55000"
    INDEXER_URL  = "https://172.21.252.96:9200"
    USERNAME     = "wazuh-wui"
    PASSWORD     = "MyS3cr37P450r.*-"
    INDEXER_USER = "admin"
    INDEXER_PASS = "SecretPassword"

    def get_token(self):
        r = requests.post(
            f"{self.MANAGER_URL}/security/user/authenticate?raw=true",
            auth=(self.USERNAME, self.PASSWORD),
            verify=False, timeout=10
        )
        return r.text.strip()

    def get_agents(self, token):
        r = requests.get(
            f"{self.MANAGER_URL}/agents?limit=5",
            headers={"Authorization": f"Bearer {token}"},
            verify=False, timeout=10
        )
        data = r.json()
        agents = []
        for a in data.get("data", {}).get("affected_items", []):
            agents.append({
                "name":    a.get("name"),
                "status":  a.get("status"),
                "os":      a.get("os", {}).get("name"),
                "ip":      a.get("ip"),
                "version": a.get("version"),
                "last_seen": a.get("lastKeepAlive")
            })
        return {
            "total": data.get("data", {}).get("total_affected_items"),
            "agents": agents
        }

    def get_alerts_by_severity(self, level_min, level_max, size=5):
        query = {
            "size": size,
            "sort": [{"@timestamp": {"order": "desc"}}],
            "query": {
                "bool": {
                    "filter": [
                        {"range": {
                            "rule.level": {
                                "gte": level_min,
                                "lte": level_max
                            }
                        }},
                        {"range": {
                            "@timestamp": {
                                "gte": "now-24h"
                            }
                        }}
                    ]
                }
            },
            "_source": [
                "@timestamp",
                "rule.description",
                "rule.level",
                "rule.groups",
                "agent.name",
                "data.srcip",
                "location"
            ]
        }
        r = requests.get(
            f"{self.INDEXER_URL}/wazuh-alerts-4.x-*/_search",
            auth=(self.INDEXER_USER, self.INDEXER_PASS),
            json=query,
            verify=False, timeout=10
        )
        hits = r.json().get("hits", {}).get("hits", [])
        alerts = []
        for hit in hits:
            src = hit.get("_source", {})
            alerts.append({
                "time":        src.get("@timestamp"),
                "rule":        src.get("rule", {}).get("description"),
                "level":       src.get("rule", {}).get("level"),
                "groups":      src.get("rule", {}).get("groups"),
                "agent":       src.get("agent", {}).get("name"),
                "source_ip":   src.get("data", {}).get("srcip"),
                "location":    src.get("location")
            })
        return alerts

    def get_all_recent_alerts(self, size=5):
        query = {
            "size": size,
            "sort": [{"@timestamp": {"order": "desc"}}],
            "query": {
                "range": {
                    "@timestamp": {"gte": "now-24h"}
                }
            },
            "_source": [
                "@timestamp",
                "rule.description",
                "rule.level",
                "agent.name",
                "data.srcip"
            ]
        }
        r = requests.get(
            f"{self.INDEXER_URL}/wazuh-alerts-4.x-*/_search",
            auth=(self.INDEXER_USER, self.INDEXER_PASS),
            json=query,
            verify=False, timeout=10
        )
        hits = r.json().get("hits", {}).get("hits", [])
        alerts = []
        for hit in hits:
            src = hit.get("_source", {})
            alerts.append({
                "time":   src.get("@timestamp"),
                "rule":   src.get("rule", {}).get("description"),
                "level":  src.get("rule", {}).get("level"),
                "agent":  src.get("agent", {}).get("name"),
                "src_ip": src.get("data", {}).get("srcip")
            })
        return alerts

    def fetch_wazuh_data(self) -> Message:
        question = self.user_question.lower()
        try:
            token = self.get_token()

            # Agent questions
            if any(w in question for w in
                   ["agent", "endpoint", "connected",
                    "device", "how many", "status"]):
                result = self.get_agents(token)

            # Critical alerts (level 15+)
            elif any(w in question for w in
                     ["critical"]):
                alerts = self.get_alerts_by_severity(15, 20)
                result = {
                    "severity": "Critical (level 15+)",
                    "count": len(alerts),
                    "alerts": alerts
                }

            # High severity (level 12-14)
            elif any(w in question for w in
                     ["high"]):
                alerts = self.get_alerts_by_severity(12, 14)
                result = {
                    "severity": "High (level 12-14)",
                    "count": len(alerts),
                    "alerts": alerts
                }

            # Medium severity (level 7-11)
            elif any(w in question for w in
                     ["medium"]):
                alerts = self.get_alerts_by_severity(7, 11)
                result = {
                    "severity": "Medium (level 7-11)",
                    "count": len(alerts),
                    "alerts": alerts
                }

            # Low severity (level 0-6)
            elif any(w in question for w in
                     ["low"]):
                alerts = self.get_alerts_by_severity(0, 6)
                result = {
                    "severity": "Low (level 0-6)",
                    "count": len(alerts),
                    "alerts": alerts
                }

            # Latest threats, malware, attacks
            elif any(w in question for w in
                     ["threat", "alert", "attack", "malware",
                      "latest", "recent", "24 hours",
                      "incident", "detected"]):
                result = {
                    "last_24h_alerts": self.get_all_recent_alerts(),
                    "medium_severity": self.get_alerts_by_severity(7, 11, 3),
                    "low_severity":    self.get_alerts_by_severity(0, 6, 3)
                }

            # Default - show everything
            else:
                result = {
                    "agents":          self.get_agents(token),
                    "recent_alerts":   self.get_all_recent_alerts(),
                    "medium_severity": self.get_alerts_by_severity(7, 11, 3),
                    "low_severity":    self.get_alerts_by_severity(0, 6, 3)
                }

        except Exception as e:
            result = {"error": str(e)}

        return Message(text=json.dumps(result, indent=2))
